// // This is a 2-bit binary counter with an active high synchronous reset. The counter decrements by 1 on each clock cycle and resets to all 0's on reset.
module binary_counter(
    input clk,
    input reset_n,
    output reg [1:0] count
    );

    always @(posedge clk) begin
        if (!reset_n)
            count <= 2'b11;
        else
            count <= count + 1;
    end
endmodule
